function generateIshiharaCanvas(canvas, question) {
  const ctx = canvas.getContext('2d');
  const centerX = 150;
  const centerY = 150;
  const radius = 140;

  ctx.clearRect(0, 0, 300, 300);

  const bgColors = generateBackgroundColors(question.colorType);
  const fgColors = generateForegroundColors(question.colorType);

  const tempCanvas = document.createElement('canvas');
  tempCanvas.width = 300;
  tempCanvas.height = 300;
  const tempCtx = tempCanvas.getContext('2d');
  tempCtx.font = 'bold 120px Arial';
  tempCtx.textAlign = 'center';
  tempCtx.textBaseline = 'middle';
  tempCtx.fillStyle = 'black';
  tempCtx.fillText(question.correctAnswer, centerX, centerY + 10);

  const imageData = tempCtx.getImageData(0, 0, 300, 300);
  const data = imageData.data;

  const fgPoints = [];
  for (let x = 0; x < 300; x += 3) {
    for (let y = 0; y < 300; y += 3) {
      const index = (y * 300 + x) * 4;
      if (data[index + 3] > 128) {
        const dist = Math.sqrt((x - centerX) ** 2 + (y - centerY) ** 2);
        if (dist < radius) {
          fgPoints.push({ x, y });
        }
      }
    }
  }

  const bgPoints = [];
  for (let i = 0; i < 1500; i++) {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * radius;
    const x = Math.floor(centerX + Math.cos(angle) * dist);
    const y = Math.floor(centerY + Math.sin(angle) * dist);
    const index = (y * 300 + x) * 4;
    if (data[index + 3] <= 128) {
      bgPoints.push({ x, y });
    }
  }

  bgPoints.forEach(point => {
    const dotRadius = 2 + Math.random() * 4;
    ctx.beginPath();
    ctx.arc(point.x, point.y, dotRadius, 0, Math.PI * 2);
    ctx.fillStyle = bgColors[Math.floor(Math.random() * bgColors.length)];
    ctx.fill();
  });

  fgPoints.forEach(point => {
    const dotRadius = 3 + Math.random() * 5;
    ctx.beginPath();
    ctx.arc(point.x, point.y, dotRadius, 0, Math.PI * 2);
    ctx.fillStyle = fgColors[Math.floor(Math.random() * fgColors.length)];
    ctx.fill();
  });
}

function generateBackgroundColors(colorType) {
  switch (colorType) {
    case 'red-green':
      return [
        '#8B7355', '#A0826D', '#B89580', '#C9A87C',
        '#D4B896', '#C4A35A', '#B8956E', '#A68B5B'
      ];
    case 'blue-yellow':
      return [
        '#7B8B6F', '#8F9E7F', '#A3B08F', '#B7C29F',
        '#9E8B7E', '#AE9B8E', '#BEAB9E', '#CEBBAD'
      ];
    case 'total':
      return [
        '#6B6B6B', '#7B7B7B', '#8B8B8B', '#9B9B9B',
        '#ABABAB', '#BBBBBB', '#CBCBCB', '#DBDBDB'
      ];
    default:
      return ['#8B7355', '#A0826D', '#B89580', '#C9A87C'];
  }
}

function generateForegroundColors(colorType) {
  switch (colorType) {
    case 'red-green':
      return [
        '#CD5C5C', '#D2691E', '#DAA520', '#B8860B',
        '#CD853F', '#D2B48C', '#BC8F8F', '#C04000'
      ];
    case 'blue-yellow':
      return [
        '#4169E1', '#1E90FF', '#00BFFF', '#87CEEB',
        '#4682B4', '#5F9EA0', '#6495ED', '#7B68EE'
      ];
    case 'total':
      return [
        '#2F2F2F', '#3F3F3F', '#4F4F4F', '#5F5F5F',
        '#1F1F1F', '#0F0F0F', '#000000', '#1A1A1A'
      ];
    default:
      return ['#CD5C5C', '#D2691E', '#DAA520', '#B8860B'];
  }
}

function startTest() {
  currentQuestionIndex = 0;
  score = 0;
  userAnswers = [];

  document.getElementById('startScreen').style.display = 'none';
  document.getElementById('testScreen').classList.add('active');

  showQuestion();
}

function showQuestion() {
  const question = testQuestions[currentQuestionIndex];
  const progress = ((currentQuestionIndex + 1) / testQuestions.length) * 100;

  document.getElementById('progressFill').style.width = `${progress}%`;
  document.getElementById('questionCount').textContent = `第 ${currentQuestionIndex + 1} / ${testQuestions.length} 题`;

  const canvas = document.getElementById('testCanvas');
  generateIshiharaCanvas(canvas, question);

  const optionsContainer = document.getElementById('options');
  optionsContainer.innerHTML = '';

  const shuffledOptions = [...question.options].sort(() => Math.random() - 0.5);

  shuffledOptions.forEach(option => {
    const btn = document.createElement('button');
    btn.className = 'optionBtn';
    btn.textContent = option;
    btn.addEventListener('click', () => selectAnswer(option));
    optionsContainer.appendChild(btn);
  });

  document.getElementById('feedback').classList.add('hidden');
  document.getElementById('nextBtn').classList.add('hidden');
}

function selectAnswer(answer) {
  const question = testQuestions[currentQuestionIndex];
  const isCorrect = answer === question.correctAnswer;

  const buttons = document.querySelectorAll('.optionBtn');
  buttons.forEach(btn => {
    btn.disabled = true;
    if (btn.textContent === question.correctAnswer) {
      btn.classList.add('correct');
    } else if (btn.textContent === answer && !isCorrect) {
      btn.classList.add('wrong');
    }
  });

  const feedback = document.getElementById('feedback');
  feedback.classList.remove('hidden');

  if (isCorrect) {
    score++;
    feedback.textContent = '✓ 回答正确！';
    feedback.className = 'feedback correct';
  } else {
    feedback.textContent = `✗ 回答错误！正确答案是 ${question.correctAnswer}`;
    feedback.className = 'feedback wrong';
  }

  userAnswers.push({
    questionId: question.id,
    answer: answer,
    correctAnswer: question.correctAnswer,
    isCorrect: isCorrect,
    colorType: question.colorType
  });

  document.getElementById('nextBtn').classList.remove('hidden');
}

function nextQuestion() {
  currentQuestionIndex++;

  if (currentQuestionIndex < testQuestions.length) {
    showQuestion();
  } else {
    showResults();
  }
}

function showResults() {
  document.getElementById('testScreen').classList.remove('active');
  document.getElementById('resultScreen').classList.add('active');

  document.getElementById('scoreDisplay').textContent = `${score} / ${testQuestions.length}`;

  const evaluation = generateEvaluation();
  document.getElementById('evaluation').innerHTML = `
    <h3>色觉评估结果</h3>
    <p>${evaluation}</p>
    <p style="margin-top: 15px; font-size: 14px; color: #888;">
      注：此测试仅供参考，不能替代专业医疗诊断。如有疑虑，请咨询专业医生。
    </p>
  `;
}

function generateEvaluation() {
  const percentage = (score / testQuestions.length) * 100;
  const redGreenWrong = userAnswers.filter(a => !a.isCorrect && a.colorType === 'red-green').length;
  const blueYellowWrong = userAnswers.filter(a => !a.isCorrect && a.colorType === 'blue-yellow').length;

  if (percentage >= 90) {
    return `您的色觉非常优秀！您能够准确分辨各种颜色，属于正常色觉范围。恭喜您拥有良好的色彩感知能力！`;
  } else if (percentage >= 70) {
    let details = [];
    if (redGreenWrong >= 2) {
      details.push('可能存在轻度红绿色觉异常');
    }
    if (blueYellowWrong >= 1) {
      details.push('可能存在轻度蓝黄色觉异常');
    }
    const detailStr = details.length > 0 ? '（' + details.join('、') + '）' : '';
    return `您的色觉基本正常${detailStr}。大部分颜色您都能够正常分辨，但在某些特定色调上可能需要更仔细的观察。建议在需要精确颜色判断的工作中多加注意。`;
  } else if (percentage >= 50) {
    let issues = [];
    if (redGreenWrong >= 3) {
      issues.push('红绿色觉异常较为明显');
    }
    if (blueYellowWrong >= 2) {
      issues.push('蓝黄色觉存在异常');
    }
    const issuesStr = issues.length > 0 ? '检测发现' + issues.join('，') : '';
    return `您的色觉存在一定程度的异常。${issuesStr}。建议您咨询专业眼科医生进行全面检查，以获得更准确的诊断结果。`;
  } else {
    return `您的色觉可能存在较明显的异常。建议您尽快前往医院眼科进行专业的色觉检查和诊断，以便了解具体情况并采取相应措施。`;
  }
}

function restartTest() {
  document.getElementById('resultScreen').classList.remove('active');
  document.getElementById('startScreen').style.display = 'block';
}

document.addEventListener('DOMContentLoaded', initApp);